#include <unordered_map>

class FreqStack {
public:
    FreqStack() {}

    void push(int val) {
        freqMap[val]++;
    }

    int pop() {
        int maxFrequency = 0;
        int result = -1;
        for (auto it = freqMap.begin(); it != freqMap.end(); it++) {
            if (it->second > maxFrequency) {
                maxFrequency = it->second;
                result = it->first;
            }
        }
        return result;
    }

private:
    std::unordered_map<int, int> freqMap;
};
